export function scale(image: string[], scaleFactor: number): string[] {
  if (scaleFactor === 1) {
    return [...image];
  }
  if (image.length === 0) {
    return [];
  }
  // Vertical scaling: duplicate each line scaleFactor times
  const result: string[] = [];
  for (const line of image) {
    for (let i = 0; i < scaleFactor; i++) {
      result.push(line);
    }
  }
  return result;
}

