export function scale(image: string[], scaleFactor: number): string[] {
  if (scaleFactor === 1) {
    return [...image];
  }
  if (image.length === 0) {
    return [];
  }
  // Horizontal scaling: repeat each character scaleFactor times
  const horizontallyScaled = image.map((line) => {
    return line
      .split("")
      .map((char) => char.repeat(scaleFactor))
      .join("");
  });

  // Vertical scaling: duplicate each line scaleFactor times
  const result: string[] = [];
  for (const line of horizontallyScaled) {
    for (let i = 0; i < scaleFactor; i++) {
      result.push(line);
    }
  }
  return result;
}

