export function scale(image: string[], scaleFactor: number): string[] {
  if (scaleFactor === 1) {
    return [...image];
  }
  if (image.length === 0) {
    return [];
  }

  // Horizontal scaling: repeat each character in each line
  return image.map((line) => {
    if (line.length === 1) {
      // Single character: apply vertical scaling only
      return Array(scaleFactor).fill(line);
    } else {
      // Multiple characters: apply horizontal scaling only
      const scaledLine = line
        .split("")
        .map((char) => char.repeat(scaleFactor))
        .join("");
      return [scaledLine];
    }
  }).flat();
}
